import{c as e,Q as r,j as d,m as a}from"./chunks/framework.CpfXsn6-.js";const i=JSON.parse('{"title":"多路复用","description":"","frontmatter":{"title":"多路复用"},"headers":[],"relativePath":"developer/mux.md","filePath":"developer/mux.md","lastUpdated":1779163937000}'),o={name:"developer/mux.md"};function s(m,t,p,n,l,_){return r(),d("div",null,[...t[0]||(t[0]=[a('<p>Trojan-Go-Next使用<a href="https://github.com/xtaci/smux" target="_blank" rel="noreferrer">smux</a>实现多路复用。同时实现了simplesocks协议用于进行代理传输。</p><p>当启用多路复用时，客户端首先发起TLS连接，使用正常trojan协议格式，但协议Command部分填入0x7f(protocol.Mux)，标识此连接为复用连接（类似于http的upgrade），之后连接交由smux客户端管理。服务器收到请求头部后，交由smux服务器解析该连接的所有流量。在每条分离出的smux连接上，使用simplesocks协议（去除认证部分的trojan协议)标明代理目的地。自顶向下的协议栈如下：</p><table tabindex="0"><thead><tr><th>协议</th><th>备注</th></tr></thead><tbody><tr><td>真实流量</td><td></td></tr><tr><td>SimpleSocks</td><td></td></tr><tr><td>smux</td><td></td></tr><tr><td>Trojan</td><td>用于鉴权</td></tr><tr><td>底层协议</td><td></td></tr></tbody></table>',3)])])}const u=e(o,[["render",s]]);export{i as __pageData,u as default};
